// Distance between two [lng, lat] arrays (Haversine approximation, km)
function calcDistance(a, b) {
  const dx = (b[0] - a[0]) * 111.32 * Math.cos(a[1] * Math.PI / 180);
  const dy = (b[1] - a[1]) * 110.574;
  return Math.sqrt(dx * dx + dy * dy);
}

// Peak hour windows: 10-minute headway (7:00-9:00, 15:00-17:00)
const PEAK_HOURS = [
  { start: 7, end: 9 },
  { start: 15, end: 17 },
];

// Returns active bus count for a route given sim hour and holiday flag
// Normal: 20-min headway | Peak: 10-min headway | Holiday: 3/route = 12 total
function getActiveBusCount(route, simHour, isHoliday) {
  if (isHoliday) return route.holidayBuses;
  const inPeak = PEAK_HOURS.some((p) => simHour >= p.start && simHour < p.end);
  return inPeak ? route.peakBuses : route.normalBuses;
}

// Pre-compute segment distances and grades for each route
ROUTES.forEach((r) => {
  r.segmentDist  = [];
  r.segmentGrade = [];
  r.totalWaypointKm = 0;
  for (let i = 0; i < r.waypoints.length - 1; i++) {
    const a = r.waypoints[i];
    const b = r.waypoints[i + 1];
    const d = calcDistance(a, b);
    r.segmentDist.push(d);
    r.totalWaypointKm += d;
    const elevDiff = (b[2] || 0) - (a[2] || 0);
    r.segmentGrade.push(d > 0 ? elevDiff / (d * 1000) : 0);
  }
});

module.exports = { ROUTES, CHARGERS, PEAK_HOURS, getActiveBusCount, calcDistance };
